then.script:
var payload = mc.getPayloadJSON();

// ================= SAFE CLEAN FUNCTION =================
function clean(obj) {

    if (obj === null || obj === "") return undefined;

    if (Array.isArray(obj)) {
        var arr = obj
            .map(clean)
            .filter(function(v){
                return v !== undefined &&
                       !(Array.isArray(v) && v.length === 0) &&
                       !(typeof v === "object" && v !== null && Object.keys(v).length === 0);
            });

        return arr.length > 0 ? arr : undefined;
    }

    if (typeof obj === "object" && obj !== null) {
        var newObj = {};

        Object.keys(obj).forEach(function(key){
            var value = clean(obj[key]);
            if (value !== undefined) {
                newObj[key] = value;
            }
        });

        return Object.keys(newObj).length > 0 ? newObj : undefined;
    }

    return obj;
}

function mapPolicy(p) {

    if (!p) return {};

    var result = {

        parties: p.parties,
        quote: p.quote,

        policyNumber: p.policyNumber,
        policyAcceptDate: p.policyAcceptDate,
        policyissuedDate: p.policyissuedDate,
        policyCancellationType: p.policyCancellationType,
        policyCancellationComments: p.policyCancellationComments,
        policyCancelledDate: p.policyCancelledDate,
        policyStatusCode: p.policyStatusCode,
        productCode: p.productCode,
        termStartDate: p.termStartDate,
        termEndDate: p.termEndDate,
        policyPeriod: p.policyPeriod,
        transactionIdentifier: p.transactionIdentifier,
        transactionTypeCode: p.transactionTypeCode,
        currentPolicyTermIdentifier: p.currentPolicyTermIdentifier,
        transactionStatusCode: p.transactionStatusCode,
        termStatusCode: p.termStatusCode,

        driverDetails: p.driverDetails,
        underWritingQuestions: p.underWritingQuestions,
        insurableObjects: p.insurableObjects,
        coverages: p.coverages,
        pricing: p.pricing,
        documents: p.documents,
        billing: p.billing,
        renewals: p.renewals,
        reinstatements: p.reinstatements,
        endorsements: p.endorsements
    };

    return clean(result) || {};
}

var finalResult = [];

if (payload) {

    if (Array.isArray(payload)) {
        finalResult = payload.map(function(item){
            return mapPolicy(item);
        });
    } else {
        finalResult = mapPolicy(payload);
    }

}

mc.setPayloadJSON(finalResult);
